import sys
class Solution:
    def uniquePaths(self, grid):
        MOD = 10**9 + 7
        m = len(grid)
        n = len(grid[0])
        sys.setrecursionlimit(1000000)
        def resolve(i, j, d):
            ci, cj = i, j
            while True:
                ni, nj = (ci, cj + 1) if d == 0 else (ci + 1, cj)
                if ni < 0 or ni >= m or nj < 0 or nj >= n:
                    return None
                if grid[ni][nj] == 0:
                    return (ni, nj)
                d = 1 - d
                ci, cj = ni, nj
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def ways(i, j):
            if i == m - 1 and j == n - 1:
                return 1
            total = 0
            for d in (0, 1):
                nxt = resolve(i, j, d)
                if nxt is not None:
                    total += ways(nxt[0], nxt[1])
            return total % MOD
        return ways(0, 0)

