var uniquePaths = function(grid) {
    const MOD = 1000000007n;
    const m = grid.length, n = grid[0].length;
    const resolve = (i, j, d) => {
        let ci = i, cj = j;
        while (true) {
            let ni, nj;
            if (d === 0) { ni = ci; nj = cj + 1; } else { ni = ci + 1; nj = cj; }
            if (ni < 0 || ni >= m || nj < 0 || nj >= n) return null;
            if (grid[ni][nj] === 0) return [ni, nj];
            d = 1 - d;
            ci = ni; cj = nj;
        }
    };
    const dp = Array.from({ length: m }, () => new Array(n).fill(0n));
    dp[0][0] = 1n;
    const cells = [];
    for (let i = 0; i < m; i++) for (let j = 0; j < n; j++) if (grid[i][j] === 0) cells.push([i, j]);
    cells.sort((a, b) => (a[0] + a[1]) - (b[0] + b[1]) || a[0] - b[0]);
    for (const [i, j] of cells) {
        const w = dp[i][j];
        if (w === 0n) continue;
        for (const d of [0, 1]) {
            const nxt = resolve(i, j, d);
            if (nxt !== null) {
                dp[nxt[0]][nxt[1]] = (dp[nxt[0]][nxt[1]] + w) % MOD;
            }
        }
    }
    return Number(dp[m - 1][n - 1] % MOD);
};
